import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"AI Worker","description":"","frontmatter":{},"headers":[],"relativePath":"projects/ai-worker.md","filePath":"projects/ai-worker.md","lastUpdated":null}'),i={name:"projects/ai-worker.md"};function n(s,e,l,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-worker" tabindex="-1">AI Worker <a class="header-anchor" href="#ai-worker" aria-label="Permalink to &quot;AI Worker&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>AI Worker</strong> is a personal tooling project: small scripts and conventions that turn recurring robotics software chores—bag checks, launch hygiene, parameter diffs—into repeatable commands with predictable outputs.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Field debugging eats calendar time when every engineer reinvents one-off utilities. This project standardizes the boring layer so attention stays on physics and interfaces.</p><h2 id="technical-scope" tabindex="-1">Technical Scope <a class="header-anchor" href="#technical-scope" aria-label="Permalink to &quot;Technical Scope&quot;">​</a></h2><ul><li>CLI wrappers around <code>ros2</code> introspection with stable JSON output for notebooks</li><li>Template repositories for <strong>ROS 2</strong> packages with CI, formatting, and changelog habits pre-wired</li><li>Lightweight dashboards from structured logs (no heavy front-end stack)</li></ul><h2 id="what-i-learned" tabindex="-1">What I Learned <a class="header-anchor" href="#what-i-learned" aria-label="Permalink to &quot;What I Learned&quot;">​</a></h2><ul><li><strong>Friction drops</strong> when defaults are excellent: naming, folder layout, and a single <code>justfile</code> or <code>Makefile</code> beat a long onboarding document.</li><li>The best tools are boring: deterministic, fast, and easy to delete when upstream fixes land.</li></ul><h2 id="related-notes" tabindex="-1">Related Notes <a class="header-anchor" href="#related-notes" aria-label="Permalink to &quot;Related Notes&quot;">​</a></h2><ul><li><a href="/articles/ros2/">ROS 2 articles</a></li><li><a href="/articles/system-engineering/">System Engineering articles</a></li><li>Sample cadence in <a href="/tech-log/2026/2026-w18.html">2026-W18 Tech Log</a></li></ul>',11)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
